#include <stdio.h>
#include <stdlib.h>
int cmp_ll(const void *a, const void *b) {
    long long A = *(const long long *)a;
    long long B = *(const long long *)b;
    return (A > B) - (A < B);
}
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        long long *root = (long long *)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &root[i]);
        qsort(root, N, sizeof(long long), cmp_ll);
        while (Q--) {
            long long x; scanf("%lld", &x);
            int lo = 0, hi = N;
            while (lo < hi) {
                int mid = lo + (hi - lo) / 2;
                if (root[mid] < x) lo = mid + 1; else hi = mid;
            }
            if (lo < N && root[lo] == x) {
                printf("0\n");
                continue;
            }
            int greater = N - lo; // roots strictly greater than x
            if (greater % 2 == 0) printf("POSITIVE\n");
            else printf("NEGATIVE\n");
        }
        free(root);
    }
    return 0;
}

