import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int Q = Integer.parseInt(st.nextToken());
            long[] roots = new long[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; i++) roots[i] = Long.parseLong(st.nextToken());
            Arrays.sort(roots);
            for (int i = 0; i < Q; i++) {
                long x = Long.parseLong(br.readLine().trim());
                int idx = Arrays.binarySearch(roots, x);
                if (idx >= 0) {
                    out.append('0').append('\n');
                } else {
                    int insertPos = -idx - 1; // first element > x
                    int greater = N - insertPos;
                    out.append((greater % 2 == 0) ? "POSITIVE" : "NEGATIVE").append('\n');
                }
            }
        }
        System.out.print(out.toString());
    }
}

