import sys, bisect

def main():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); Q = int(next(it))
        roots = [int(next(it)) for _ in range(N)]
        roots.sort()
        for __ in range(Q):
            x = int(next(it))
            idx = bisect.bisect_left(roots, x)
            if idx < N and roots[idx] == x:
                out_lines.append('0')
            else:
                greater = N - idx
                out_lines.append('POSITIVE' if greater % 2 == 0 else 'NEGATIVE')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

