const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let pos = 0;
if (data.length === 0) process.exit(0);
const T = Number(data[pos++]);
let output = [];
function lowerBound(arr, target) {
  let l = 0, r = arr.length;
  while (l < r) {
    const m = (l + r) >> 1;
    if (arr[m] < target) l = m + 1; else r = m;
  }
  return l;
}
for (let tc = 0; tc < T; ++tc) {
  const N = Number(data[pos++]);
  const Q = Number(data[pos++]);
  const roots = new Array(N);
  for (let i = 0; i < N; ++i) roots[i] = Number(data[pos++]);
  roots.sort((a, b) => a - b);
  for (let i = 0; i < Q; ++i) {
    const x = Number(data[pos++]);
    const idx = lowerBound(roots, x);
    if (idx < N && roots[idx] === x) {
      output.push('0');
    } else {
      const greater = N - idx;
      output.push(greater % 2 === 0 ? 'POSITIVE' : 'NEGATIVE');
    }
  }
}
console.log(output.join('\n'));
